INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 1, '過去形', 'I was tired last week.', '先週私は疲れていました。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 2, '過去形', 'We visited Toronto last year.', '私たちは去年トロントを訪れました。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 3, '過去形', 'Where was he an hour ago? – He was in his room.', '一時間前、彼はどこにいたの？―自分(彼)の部屋にいたよ。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 4, '過去進行形', 'She was playing the guitar then.', '彼女はその時ギターを弾いていました。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 5, '過去進行形', 'The students were not listening to the teacher then.', 'その時生徒たちは先生の言うことを聴いていなかった。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 6, '過去進行形', 'Why was your girlfriend crying?', 'あなたの彼女はなぜ泣いていたのですか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 7, 'when節', 'When summer comes, a lot of people go to Lake Ontario.', '夏が来るとたくさんの人がオンタリオ湖に行きます。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 8, 'when節', 'I was doing my homework when my mother came home.', 'お母さんが家に帰ってきた時、私は宿題をしていました。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 9, 'when節', 'What was your sister doing when you came back home from school?', 'あなたが学校から帰った時、あなたのお姉さんは何をしていましたか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 10, '一般動詞のSVC', 'He looks (appears) very sad.', '彼はとても悲しそうだ（悲しそうに見える）。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 11, '一般動詞のSVC', 'My grandmother’s (grandma’s) hair is turning gray.', 'おばあちゃんの髪は白髪になってきています。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 12, '一般動詞のSVC', 'What did the boy become when he grew up?', 'その男の子は成長して、何になりましたか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 13, 'SVO + to (for)', 'He showed a picture to us.', '彼は一枚の写真を私たちに見せた。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 14, 'SVO + to (for)', 'Did someone lend a bicycle to you?', '誰かがあなたに自転車を貸してくれたんですか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 15, 'SVO + to (for)', 'How much money did you give to the man?', 'あなたはその男にお金をいくらあげたのですか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 16, 'SVOO', 'My (older) brother gave me a present.', '兄が僕にプレゼントをくれた。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 17, 'SVOO', 'My mother made my friends some cookies.', 'お母さん僕の友達にクッキーを作ってくれた。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 18, 'SVOO', 'Does your father teach you English?', 'あなたのお父さんがあなたに英語を教えてくれるのですか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 19, '単純未来のwill', 'I will be twenty nine years old in July.', '私は7月に29歳になります。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 20, '単純未来のwill', 'Will it be rainy the day after tomorrow? Will it rain ～でもOK！', '明後日は雨が降るでしょうか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 21, '単純未来のwill', 'When will they come to Canada? – They will come next year.', '彼女たちはいつカナダに来るのでしょうか？ー来年来るでしょう。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 22, '意志未来のwill', 'I will do my best.', '私はベストを尽くします！' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 23, '意志未来のwill', 'I will not (won’t) see her again.', '私はもう二度と彼女には会いません。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 24, '意志未来のwill', 'I will finish this task (assignment) today.', '今日この課題を終わらせるぞ。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 25, '依頼のwill とshall （申し出・誘い）', 'Will you please help me? – Sure.', '私を手伝ってくれますか？－もちろん。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 26, '依頼のwill とshall （申し出・誘い）', 'Will you have some more coffee?', 'もう少しコーヒーはいかがですか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 27, '依頼のwill とshall （申し出・誘い）', 'Shall we play basketball in the park? – No, let’s not.', '公園でバスケをしましょうよ？－いや、やめとこう。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 31, 'be going to', 'I am going to meet him in front of the station tonight.', '私は今夜駅前で彼と会う予定です。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 32, 'be going to', 'When are you going to leave Vancouver? – I’m going to leave tomorrow.', 'あなたはいつバンクーバーを出発する予定ですか？－明日発つ予定です。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 33, 'be going to', 'I’m going to travel around North America during the summer vacation.', '夏休みは北米を旅してまわる予定です。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 34, 'must/may', 'You must do your homework by tomorrow.', 'あなたは宿題を明日までにしなければいけません。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 35, 'must/may', 'A child must not go to the forest alone.', '子供はその森に一人で行ってはなりません。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 36, 'must/may', 'May I look at this diary? – No, you may not.', 'この日記を見てもいいですか？－いいえ、いけません。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 37, 'have to', 'Students all have to wear uniforms in this school.', 'この学校では学生たちはみんな制服を着なくてはならない。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 38, 'have to', 'She didn’t have to wash the dishes.', '彼女はお皿を洗う必要はありませんでした。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 39, 'have to', 'What did you have to do? – She had to practice the piano.', 'あなたは何をしなければならなかったのですか？―ピアノを練習しなければなりませんでした。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 40, 'be able to', 'You will be able to learn many things in Toronto.', 'トロントであなたは多くのことを学べるでしょう。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 41, 'be able to', 'Who was able to catch the dog?', '誰がその犬を捕まえられましたか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 42, 'be able to', 'Was he able to speak with the teacher in English? – Yes, he was.', '彼は先生と英語で話すことができましたか？－はい、できました。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 43, '感嘆文', 'How kind you are!', 'あなたはなんて親切なんだろう！' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 44, '感嘆文', 'How hard she studies!', '彼女はなんて一生懸命勉強するんだろう！' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 45, '感嘆文', 'What an interesting movie it was!', 'なんておもしろい映画だったろう！' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 46, '不定詞―名詞的用法', 'I want to go to Canada some day.', '僕はいつかカナダに行きたい。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 47, '不定詞―名詞的用法', 'Her hobby is to watch baseball.', '彼女の趣味は野球を観ることです。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 48, '不定詞―名詞的用法', 'To be with him is a lot of fun.', '彼といることはとても楽しいです。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 49, '不定詞―副詞的用法（目的）', 'I went to a book store to buy some books.', '私は本を何冊か買いに本屋さんに行った。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 50, '不定詞―副詞的用法（目的）', 'I am going to get up early tomorrow morning to run (jog).', '私はランニングするために明日の朝早く起きるつもりです。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 51, '不定詞―副詞的用法（目的）', 'My (younger/little) brother has to study for many hours every day to pass the exam.', '弟は試験に受かるために毎日何時間も勉強しなければならない。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 52, '不定詞―副詞的用法（感情の原因）', 'I am happy (glad) to meet you.', 'あなたに会えてうれしいです。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 53, '不定詞―副詞的用法（感情の原因）', 'We were surprised to hear her story.', '彼女の話を聞いて私たちはとても驚いた。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 54, '不定詞―副詞的用法（感情の原因）', 'Your parents will be pleased to receive your present.', 'あなたのご両親はあなたのプレゼントを受け取って喜ぶでしょう。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 55, '不定詞―形容詞的用法', 'I have my homework to do today.', '私には今日しなければならない(するべき)宿題があります。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 56, '不定詞―形容詞的用法', 'Did the baby want something to eat?', 'その赤ちゃんは何か食べるものが欲しかったのですか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 57, '不定詞―形容詞的用法', 'I don’t have anything to do today. または　I have nothing to do today.', '私は今日何もすることがない。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 58, '動名詞', 'Will he stop (give up) smoking?', '彼はたばこを吸うのをやめますか。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 59, '動名詞', 'She is good at speaking Chinese.', '彼女は中国語を話すのが得意です。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 60, '動名詞', 'What (musical) instrument do you like playing?', 'あなたはどんな楽器を弾くのが好きですか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 61, 'as-as 原級比較', 'This temple is as old as that temple (one).', 'このお寺はあのお寺と同じくらい古い。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 62, 'as-as 原級比較', 'Are these cherries as sweet as those cherries (ones)?', 'これらのさくらんぼはあれらと同じくらい甘いですか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 63, 'as-as 原級比較', 'He can’t speak Japanese as well as you do.', '彼は君ほど上手には日本語を話せない。' FROM public.lessons WHERE course_key = 'basic';
