INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 65, '比較級 -er形', 'It will be much colder tomorrow than today.', '明日は今日よりずっと寒くなるでしょう。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 66, '比較級 -er形', 'His baggage looked heavier than mine.', '彼の荷物は僕のより重そうに見えた。' FROM public.lessons WHERE course_key = 'basic';
