INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 69, '最上級 -est形', 'This is the best way of all.', 'これがすべての中で一番いい方法です。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 70, '比較級 more', 'Is Chinese more useful than English?', '中国語は英語より役に立ちますか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 71, '比較級 more', 'Time is more important than money.', '時間はお金より大切です。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 72, '比較級 more', 'This country is more dangerous than your country (yours).', 'この国は君の国より危険だ。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 73, '最上級 most', 'He is one of the most famous writers in the world.', '彼は世界で最も有名な作家の一人です。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 74, '最上級 most', 'That black car is the most expensive of these ten cars.', 'この10台の車の中であの黒い車が一番高い。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 75, '最上級 most', 'The smallest orange was the most delicious.', '一番小さなオレンジが一番おいしかった。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 76, '比較級―副詞', 'My brother can run faster than me.', '弟は僕より速く走れます。' FROM public.lessons WHERE course_key = 'basic';
