INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 78, '比較級―副詞', 'Does she speak Japanese more fluently than you do?', '彼女はあなたより流暢に日本語を話しますか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 79, '最上級―副詞', 'Bob walked (the) most fluently of them all.', 'ボブは3人のうちで一番ゆっくり歩きました。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 80, '最上級―副詞', 'Who sleeps (the) longest in your family? – My (older) brother does.', 'あなたの家族では誰が一番長く眠りますか？―兄です。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 81, '最上級―副詞', 'Taro listened to the teacher (the) most carefully of those children.', 'あの子供たちの中でタロウが一番注意深く先生の言うことを聴きました。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 82, '比較級、最上級を使った疑問詞の文', 'Which is smaller, his room or hers (her room)? 部屋の広い・狭いを表す場合は large/big, small を使いましょう。 日本語を直訳してnarrowにしないように注意！', '彼の部屋と彼女のでは、どちらが狭いですか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 83, '比較級、最上級を使った疑問詞の文', 'Who is the smartest in your class?', 'あなたのクラスでは誰が一番賢いですか？' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 84, '比較級、最上級を使った疑問詞の文', 'Which subject do you like (the) best? – I like math (the best).', 'あなたはどの科目が一番好きですか？―数学です。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 85, '現在完了―継続', 'I have lived in this city for ten years.', '私はこの都市に10年住んでいます。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 86, '現在完了―継続', 'I haven’t seen him since Sunday.', '私は日曜日からずっと彼に会っていない。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 87, '現在完了―継続', 'We have been on this train for four hours.', '私たちはこの列車に4時間乗っています。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 88, '現在完了―完了', 'I have just had (eaten) breakfast.', '僕はちょうど朝食を食べたところです。' FROM public.lessons WHERE course_key = 'basic';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 89, '現在完了―完了', 'We haven’t received (got) a letter from her yet.', '私たちはまだ彼女からの手紙を受け取っていません。' FROM public.lessons WHERE course_key = 'basic';
