INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 146, '初級編', 'Can I have another glass of milk?', 'もう一杯牛乳をいただけますか？' FROM public.lessons WHERE course_key = 'beginner';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 147, '初級編', 'Where were these clothes made? ※clothesの発音に注意しましょう。 単数・複数とも同じ発音 [klóʊ(ð)z] です。', 'これらの服はどこで作られたのですか？' FROM public.lessons WHERE course_key = 'beginner';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 148, '初級編', 'My boss has been studying English for two years.', '私の上司は英語を二年間勉強しています。' FROM public.lessons WHERE course_key = 'beginner';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 149, '初級編', 'The lawyer looks very tired, doesn’t he (she)? – Yes, he (she) does.', 'あの弁護士はとても疲れているように見えますね？ーはい、そうですね。' FROM public.lessons WHERE course_key = 'beginner';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 150, '初級編', 'Could you please tell me the way to the station?', '駅への道を教えてくれますか？' FROM public.lessons WHERE course_key = 'beginner';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 1, '現在分詞修飾', 'The sleeping cat is cute.', '眠っている(その)猫はかわいい。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 2, '現在分詞修飾', 'Who is the boy speaking English?', '英語を話しているその男の子は誰ですか？' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 3, '現在分詞修飾', 'The woman playing the piano was his aunt.', 'ピアノを弾いている女性は彼のおばさんでした。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 4, '過去分詞修飾', 'Look at that broken glass.', 'あの割れたグラスを見なさい。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 5, '過去分詞修飾', 'He wants to buy a car made in Japan.', '彼は日本製の車を買いたがっています。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 6, '過去分詞修飾', 'English is a language spoken around the world.', '英語は世界中で話される言語です。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 7, '関係代名詞・主格＜人＞', 'Can you see the students who (that) are running in the park?', '公園で走っている生徒たちが見えますか？' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 8, '関係代名詞・主格＜人＞', 'Do you remember the teacher who (that) spoke to us yesterday?', '君は昨日僕たちに話しかけた先生を覚えているかい？' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 9, '関係代名詞・主格＜人＞', 'The woman who (that) is studying hard will soon be able to speak English.', '一生懸命勉強しているその女性はすぐに英語が話せるようになるでしょう。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 10, '関係代名詞・主格＜人以外＞', 'Is this a train which (that) leaves at six o’clock?', 'これは6時に出発する電車ですか？' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 11, '関係代名詞・主格＜人以外＞', 'What is the building which (that) stands near the park?', '公園のそばに建っている建物は何ですか？' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 12, '関係代名詞・主格＜人以外＞', 'They played on the hill which (that) was covered with flowers.', '彼女たちは花でおおわれた丘で遊んだ。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 13, '関係代名詞・所有格whose とof which', 'The man whose bike broke down went to work by bus.', '自転車が壊れてしまったその男性は、バスで仕事に行った。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 14, '関係代名詞・所有格whose とof which', 'At the library, I found a book the cover of which was interesting (funny).', '私は図書館で面白い表紙の本を見つけた。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 15, '関係代名詞・所有格whose とof which', 'The house the garden of which is large is my aunt’s.', 'その庭が広い家は私のおばさんのものです。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 16, '関係代名詞・目的格＜人＞', 'That is the singer (whom / that) he respects.', 'あの人が、彼が尊敬している歌手です。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 17, '関係代名詞・目的格＜人＞', 'The man (whom / that) we met yesterday is a famous actor.', '私たちが昨日会った男性は有名な俳優です。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 18, '関係代名詞・目的格＜人＞', 'She is a writer (whom / that) everybody knows.', '彼女は誰もが知ってる作家です。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 19, '関係代名詞・目的格＜人以外＞', 'That is a picture (which / that) she painted(draw).', 'あれは彼女が描いた絵です。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 20, '関係代名詞・目的格＜人以外＞', 'The cheesecake (which / that) she baked yesterday was delicious.', '昨日彼女が焼いたチーズケーキはおいしかった。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 21, '関係代名詞・目的格＜人以外＞', 'What is the language (which / that) he has been studying for three years?', '彼が3年間勉強している言語は何ですか？' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 22, '先行詞を含む関係代名詞what', 'I could not understand what my father said.', '私は父の言ったことが理解できなかった。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 23, '先行詞を含む関係代名詞what', 'What the government did was right.', '政府がしたことは正しかった。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 24, '先行詞を含む関係代名詞what', 'What your girlfriend wants you to do is (to) write to them more often.', '君の彼女が君にして欲しいことは、もっと頻繁に手紙を書くことだよ。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 25, '関係代名詞where', 'That is the hospital where he was born.', 'あれは彼が生まれた病院です。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 26, '関係代名詞where', 'This is the place where I wrote the letter.', 'ここが、私がその手紙を描いた場所です。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 27, '関係代名詞where', 'We want to go to a store where we can buy something to drink.', '僕たちは何か飲み物を買える店に行きたい。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 28, '関係副詞when', 'January is the month when it snows a lot.', '1月は雪がたくさん降る月です。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 29, '関係副詞when', 'Will you please tell me the time when the teacher will come here?', '先生がここにやってくる時間を教えてくれますか？' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 30, '関係副詞when', 'Does he know the time when the plane will arrive?', '彼は飛行機が到着する時間を知っていますか？' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 31, '原形不定詞・知覚', 'I heard him say something.', '私は彼が何か言うのを聞きました。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 32, '原形不定詞・知覚', 'Did you feel the building shake?', 'あなたは建物が揺れるのを感じましたか？' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 33, '原形不定詞・知覚', 'She noticed him leave the room.', '彼女は彼が部屋を出る(去る)のに気づいた。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 34, '原形不定詞・使役', 'The teacher made the students study Germany every day.', '先生は生徒たちに毎日ドイツ語を勉強させた。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 35, '原形不定詞・使役', 'My father had my mother bring a glass of water.', '父は母に水を一杯持ってきてもらった(持ってこさせた)。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 36, '原形不定詞・使役', 'Are you going to let your child go abroad alone?', 'あなたはお子さんを一人で外国に行かせてあげるつもりですか。' FROM public.lessons WHERE course_key = 'participle';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 1, '中級編', 'He went to Toronto to study English when he was young.', '彼は若い時に、英語を学ぶためにトロントに行きました。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 2, '中級編', 'I think (that) he has lived in this country for more than (over) three years.', '私は、彼はこの国に3年以上住んでいると思います。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 3, '中級編', 'Children have already done their homework, haven’t them?', 'もう子供たちは宿題したよね？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 4, '中級編', 'Do you think that this desk is made of iron?', 'あなたはこの机は鉄でできていると思いますか？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 5, '中級編', 'I want to see the tallest student in this class!', '私はこのクラスで一番背の高い生徒と会いたい！' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 6, '中級編', 'Who came to this room to see me? – Your student did.', '誰が私に会いにこの部屋まで来たんですか？－あなたの生徒です。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 7, '中級編', 'When I saw him the other day, he said (that) he was going to learn English.', '先日彼に会ったとき、彼は英語を習うつもりだと言った。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 8, '中級編', 'I believe that this movie will be watched by many people.', '私はこの映画は多くの人に見られることと信じている。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 9, '中級編', 'When I went to the park yesterday morning, there weren’t any children.', '私が昨日の朝その公園に行ったとき、子供が一人もいなかった。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 10, '中級編', 'When other children were playing outside, I had to practice the piano at home.', '他の子どもたちが外で遊んでいるとき、私は家でピアノの練習をしなければならなかった。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 11, '中級編', 'He said that he didn’t have any time to talk to (with) me. / He said that he had no time to talk to (with) me.', '彼は、僕と話す時間はないと言った。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 12, '中級編', 'I think (that) studying history is important.', '歴史を勉強することは大切だと思う。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 13, '中級編', 'Who must (has to) clean the bathroom? – I must (have to) (do). ※tips: カナダではトイレを washroom ということが多いです。', '誰がトイレを掃除しなければならないのですか？－僕です。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 14, '中級編', 'This fruit smells better than that one.', 'この果物はあの果物よりいい香りがする。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 15, '中級編', 'The teacher looks angry, doesn’t he (she)?', '先生は怒ってるみたいだね？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 16, '中級編', 'Which novel do you want to read? – I want to read this one.', '君はどっちの小説を読みたいの？－この本が読みたい。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 17, '中級編', 'I met her once when I lived in Canada.', 'カナダに住んでいた時、僕は一度彼女に会ったことがある。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 18, '中級編', 'How many cups of tea have you drunk (had) since you got up? – I think (that) I have drunk (had) three or four cups (of tea).', '君は起きてから何杯紅茶を飲んだ？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 19, '中級編', 'I didn’t know that her hobby was playing the violin.', '僕は彼女の趣味がヴァイオリンだと知らなかった。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 20, '中級編', 'My mother looks younger than five years ago.', '母は5年前より若く見える。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 21, '中級編', 'How many countries have you ever traveled?', 'あなたは今まで何か国旅行しましたか？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 22, '中級編', 'I think that the cake has been eaten by the dog.', 'そのケーキは犬に食べられたんだと思う。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 23, '中級編', 'Will you please lend me something to wipe with? – Sure.', '僕に何か拭くものを貸してくれるかい？―どうぞ。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 24, '中級編', 'When I visited his house last night, he was watching TV with his friend(s).', '僕が昨日の夜彼の家を訪れたとき、彼は友達とテレビを見ていた。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 25, '中級編', 'He studied harder than any other student for the examination.', '彼はそのテストのために他のどの生徒よりも一生懸命勉強した。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 26, '中級編', 'I didn’t know (that) he liked fish better than meat. ※fishは数えられる名詞ですが、単数・複数ともに同じ形 fish となります。', '僕は彼が肉より魚の方が好きだとは知らなかった。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 27, '中級編', 'You have never been to Niagara Falls, have you? – No, I haven’t.', 'あなたはナイアガラの滝に一度も行ったことがないのですね？―はい、行ったことないです。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 28, '中級編', 'It began to rain suddenly when I went out.', '私が外に出たとき、雨が突然降り始めました。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 29, '中級編', 'This dish smells good, doesn’t it?', 'この料理はいい香りがしますね？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 30, '中級編', 'How do you live to keep your health?', '健康であり続けるためどのように生活していますか？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 31, '中級編', 'How careless you are to leave your car key behind!', '車の鍵を置き忘れるなんて、君は何て不注意なんだ！' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 32, '中級編', 'Falling in love is much simpler than staying (keeping) in love.', '恋に落ちることは、恋をし続ける事よりずっと単純だ。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 33, '中級編', 'The soup tasted much better than it looked.', 'そのスープは見た目よりずっとおいしかった。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 34, '中級編', 'What is the most important to master English?', '英語をマスターするためには何が一番重要ですか？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 35, '中級編', 'I can’t believe that many people like playing video games better than reading books.', '多くの人が本を読むより、ゲームをする方が好きなことが信じられない。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 36, '中級編', 'She doesn’t know that her husband has already decided to buy the car.', '夫がその車を買うと既に決めてしまったことを、彼女は知らない。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 37, '中級編', 'When he told his girlfriend the news, she began to cry suddenly.', '彼がガールフレンドにその知らせを伝えたとき、彼女は突然泣き始めた。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 38, '中級編', 'How many books have you read since you began to go to this school?', '君はこの学校に通い始めてから何冊本を読んだの？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 39, '中級編', 'When she passed the exam, she was more surprised than anyone else.', '彼女がその試験に受かった時、他の誰よりも彼女自身が驚いた。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 40, '中級編', 'The student kept walking without greeting anyone.', 'その学生は挨拶もしないで歩き続けた。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 41, '中級編', 'The woman has been eating only bananas for more than a week to lose weight.', 'その女性は体重を減らすために1週間以上もバナナだけを食べている。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 42, '中級編', 'I think the English teacher has been in Japan for more than five years.', '英語の先生は5年以上日本にいると思うよ。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 43, '中級編', 'Which is the best of these books to study economy?', '経済学を勉強するには、これらの本の中でどれが一番いいですか？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 44, '中級編', 'You should realize that you can’t be good at playing sports without practicing.', '練習せずにはスポーツは上手になれないことに気づいた方がいい。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 45, '中級編', 'Who are you going to be picked up?', '誰に迎えに来てもらう予定なの？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 46, '中級編', 'Being able to write English is much more important than being able to speak it in this job.', 'この仕事では、英語を書くことの方が話せる事よりずっと重要です。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 47, '中級編', 'I believe that my daughter will be as tall as I.', '娘は私と同じくらい背が高くなると信じてる。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 48, '中級編', 'When he was about to leave home, the telephone began to ring.', '彼がちょうど家を出ようとしていた時、電話が鳴り始めた。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 49, '中級編', 'He has been given many chances since he began to work for A.', 'A社で働き始めてから、彼は多くのチャンスを与えられてきている。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 50, '中級編', 'My brother began to study mathematics very hard to be a scientist.', '僕の兄は科学者になるために数学の猛勉強を始めた。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 51, '中級編', 'Did you still have a lot of homework to do when the others went to bed?', '他の人が寝るとき、あなたにはまだやらなければならない宿題がたくさんあったのですか？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 52, '中級編', 'What language must I learn after I go to the university? / What language do I have (need) to learn after I go to the university?', 'その大学に進学した後、何語を学ばなければいけませんか？' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 53, '中級編', 'I had to drink many cups of coffee to stay up late.', 'あの日は遅くまで起きてるために何杯もコーヒーを飲まなきゃいけなかった。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 54, '中級編', 'When I see the teacher next time, I will speak better than (I did) today.', '今度先生に会ったら、今日よりうまく話すぞ。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 55, '中級編', 'I can’t decide to carry out this plan without talking to you.', '僕はきみと話さずにこの計画の実行を決めるわけにはいかない。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 56, '中級編', 'When the journalist visited Japan for the first time, most houses were made of wood.', 'そのジャーナリストが初めて日本を訪れたとき、ほとんどの家は木造だった。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 57, '中級編', 'The man was told by his doctor that he had to stay in bed for a few days.', 'その男性はお医者さんに数日間寝ていなければならないと言われた。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 58, '中級編', 'What a fast runner you are to get there in ten minutes.', 'そこに10分で着くなんて、なんて走るのが速いんだろう。(runner)' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 59, '中級編', 'To study biology will be very useful for you.', '生態学を勉強することは、あなたにとってとても役立つでしょう。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 60, '中級編', 'When the leaves turn red, I feel a little sad.', '木の葉が赤く染まると、少し寂しくなる。' FROM public.lessons WHERE course_key = 'intermediate';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 1, '上級編', 'Let’s go to the library where we went yesterday. ー Yes, let’s.', '昨日行った図書館に行こうよ。―うん、行こう。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 2, '上級編', 'You will be able to know the story when she comes back.', '彼女が帰ってきたら（帰ってきたとき）、君はその話を知ることができるだろう。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 3, '上級編', 'What is the subject (Which/that) your mother liked (the) best when she was a student? ー It is geography.', 'あなたのお母さんが学生時代に1番好きだった科目はなんですか？ー地理です。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 4, '上級編', 'Can (May)I let her read the book when it arrives? – Yes, you can (may).', 'その本が届いたら（届くとき）、彼女に読ませてもいいですか？' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 5, '上級編', 'The book (which/that) her father wrote will be read in many countries.', '彼女のお父さんが書いた本は多くの国で読まれているだろう。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 6, '上級編', 'The clock (which/that) you saw has been at my home since I was a child.', '君が見た時計は、僕が子供の頃から我が家にいます。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 7, '上級編', 'How pretty the baby (whom/that) I met at the park was!', '公園であった赤ちゃんはなんてかわいかったんだろう！' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 8, '上級編', 'I wonder what she wanted me to do.', '彼女は僕に何をして欲しかったんだろう。(wonderを使って)' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 9, '上級編', 'Who came to the office while I was away (out)?', '僕の留守中に、誰かオフィスに来ましたか？' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 10, '上級編', 'Have you watched the movie (which/that) I lent (to) you last week yet? ー No, I haven’t.', '私があなたに先週貸した映画をもう見ましたか？ーいえ、まだです。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 11, '上級編', 'As he was hungry, he asked his mother to make lunch.', 'お腹がすいていたので、彼はお母さんに昼食を作るように頼んだ。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 12, '上級編', 'There was a beautiful castle in the town where she was born.', '彼女の生まれた町には綺麗なお城があった。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 13, '上級編', 'The man (whom/that) I met yesterday was much taller than him [he is].', '私がきのう会った男の人は彼よりずっと背が高かった。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 14, '上級編', 'As there were many people (whom/that) she knew in the room, she kept smiling.', '部屋の中には彼女の知っている人がたくさんいたので、彼女は笑い続けていました。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 15, '上級編', 'How many pieces of bread did the man (who/that) you saw at the restaurant eat?', 'あなたがそのレストランで見た男の人は、パンをいくつ食べたのですか？' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 16, '上級編', 'You don’t understand why she is loved by many people, do you?', 'あなたは、彼女がなぜ多くの人に愛されているのか、わからないのですね？' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 17, '上級編', 'The student who came from Canada to make friends has been studying Japanese at this school since I first met him.', '友達を作るためにカナダから来たその学生は、私が彼に初めて会った時からずっとこの学校で日本語を勉強している。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 18, '上級編', 'She wanted her boyfriend to notice (that) she had had [got] a hair cut.', '彼女は恋人に自分が髪を切ったことを気づいて欲しかった。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 19, '上級編', 'He told his wife not to let their son sleep on the couch.', '彼は妻に、息子をソファーで寝かせるなと言った。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 20, '上級編', 'Will the children who grew up in a city be surprised to see mountains?', '都会で育ったその子供たちは山を見て驚くだろうか？' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 21, '上級編', 'The language which [that] George is studying now is not spoken by very many people.', 'ジョージが今勉強している言語はあまり多くの人に話されていない。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 22, '上級編', 'The musician whose name is known to everyone will come to this town next month to hold a concert.', 'その名がみんなに知られている音楽家がコンサートを開くため来月この町に来る。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 23, '上級編', 'Have you ever been to a house which [that] is made of brick? / Have you ever been to a house made of brick? – Yes, I have.', 'あなたはレンガでできた家に行ったことありますか？ーはい、あります。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 24, '上級編', 'Although I wanted her to draw a picture, he made his sister do it.', '僕は彼女に絵を描いて欲しかったのだが、彼は妹にそれをやらせた。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 25, '上級編', 'I want you to tell me why John is in a good mood [humor].', '僕は君にジョンがなぜ機嫌がいいのか教えて欲しい。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 26, '上級編', 'When I saw her this morning, she said that she was going to climb a mountain.', '今朝彼女に会ったとき、彼女は山に登りに行くところだ、と言いました。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 27, '上級編', 'The rain made us give up going out.', '雨のため我々は外出するのを諦めなければならなかった。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 28, '上級編', 'I wonder if taking a walk before breakfast keeps her healthy.', '朝食前に散歩するので彼女は健康なのかしら？' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 29, '上級編', 'As he is very smart, he will be able to solve a question (that/which) you can’t.', '彼はとても頭がいいので、君には分からない問題も解けるだろう。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 30, '上級編', 'She doesn’t think (that) it is necessary to go there.', '彼女は、そこに行くことが必要だとは思わない。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 31, '上級編', 'He spoke to a woman (who was) walking on the street to ask her where the station was.', '彼は駅がどこにあるか聞くために道を歩いている女性に話しかけた。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 32, '上級編', 'The girl whose mother was a teacher decided to study education at university.', 'お母さんが先生のその少女は大学で教育学を学ぶことを決めた。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 33, '上級編', 'Which is the house where [in which] he lives? ー That one (is).', 'どちらが、彼が住んでいる家ですか？ーあれです。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 34, '上級編', 'Although he went to France to learn French, his French is worse than mine.', '彼はフランス語を覚えるためにフランスに行ったけれど、彼のフランス語は私の（フランス語）より下手だ。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 35, '上級編', 'I want you to lend me the novel when you finish reading it.', '君がその小説を読み終わったら（終わったとき）、僕に貸してほしい。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 36, '上級編', 'Have you already sold the bag (which/that) you bought only last month?', '君は先月買ったばかりのカバンをもう売ってしまったのかい？' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 37, '上級編', 'It will be very difficult [hard] to make her do this job.', '彼女にこの仕事をやらせることはとても難しいだろう。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 38, '上級編', 'When he got up in the morning, he felt disappointed to find (that) it was rainy.', '彼は朝起きたとき、天気が悪いことを知って(見つけて)がっかりした。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 39, '上級編', 'The watch (which/that) he broke has just been fixed.', '彼が壊した時計がちょうど直されたところです。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 40, '上級編', 'It is hard for her who stays up late every day to get up early in the morning.', '毎日夜更かしする彼女にとって、朝早く起きるのは辛い。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 41, '上級編', 'There were several accidents on this road on the day when it rained a lot.', '雨がたくさん降ったその日、この道でいくつか事故が起こりました。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 42, '上級編', 'Will the children who have never seen giraffes be surprised when they go to the zoo?', 'キリンを見たことがないその子供たちは動物園に行ったら驚くでしょうか？' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 43, '上級編', 'When she was asked how old she was, she answered that she was thirty although [though] she was actually forty.', '何歳なのか聞かれたとき、実は40歳なのに、彼女は30歳だと答えた。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 44, '上級編', 'As he [she] didn’t know how to cook, the child had to wait for his [her] mother to come home.', 'どうやって料理をするのかわからなかったので、その子はお母さんが帰ってくるのを待たなければならなかった。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 45, '上級編', 'The boy who [that] wanted to get a good mark on a test than anybody else in the class studied till late at night.', 'クラスの他の誰よりもテストでいい点を取りたいと思っているその少年は、夜遅くまで勉強した。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 46, '上級編', 'Although [though] her mother wants her to be [become] a doctor, she has wanted to be a teacher since she was a child.', '彼女の母親は彼女に医者になって欲しいと思っているが、彼女は子供の頃からずっと先生になりたいと思っている。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 47, '上級編', 'The coffee (that/which) my mother made smells very good.', 'お母さんが作ったコーヒーはとても良い匂いがする。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 48, '上級編', 'When he was asked why he came home so late by his wife, he answered that he went to watch a baseball game with his colleagues.', '妻にどうしてそんなに遅く帰宅したのか聞かれた時、彼は同僚たちと野球観戦に行ったのだと答えた。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 49, '上級編', 'The foreigner who came to Canada only last month asked me to give him [her] English lessons.', '先月カナダに来たばかりのその外国人は私に英語のレッスンをしてくれと頼んだ。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 50, '上級編', 'Finally, they decided to let their daughter marry the guy [whom/that] she had been going out with for six years.', 'ついに彼らは娘を6年間付き合っているその男と結婚させてやることに決めた。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 51, '上級編', 'A man whom I have known for over twenty years is going to quit the company [which/that] he now works for next month to change jobs.', '私の20年来の知り合いである男性は、転職のために来月現在勤めている会社を辞める予定だ。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 52, '上級編', 'A friend of mine whose cousin lives in Germany says that he is going to go there this winter with his brother.', 'いとこがドイツに住んでいる僕の友人は、今年の冬弟と共にドイツに行くつもりだと言っている。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 53, '上級編', 'Have you ever met a girl who [that] cooks better than Satoko?', 'さとこより料理が上手な少女に会ったことがありますか？' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 54, '上級編', 'The boy who was asked what he was doing by a teacher began to run as fast as he could [possible].', '教師に何をしているのかと尋ねられたその少年はできる限り速く走り始めた。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 55, '上級編', 'The child whose parents worked played in a park to kill time after school.', '両親が働いているその子供は放課後時間をつぶすために公園で遊んだ。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 56, '上級編', 'When I told my mother that the curry (which/that) she had made was too spicy for me to eat, she said that she had never heard anybody say such a rude thing.', 'お母さんに、お母さんが作ったカレーが辛すぎて僕は食べられないと言うと、お母さんは誰かがそんなに失礼なことを言うのを聞いたことがないと言った。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 57, '上級編', 'The weather forecast says that it will be fine today in the town where it snowed yesterday.', '昨日雪が降ったその町では、今日は晴れるだろうと、天気予報は言っている。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 58, '上級編', 'The park around which I run in the morning is visited by many people on holidays.', '私が朝周囲を走っている公園は、休日には多くの人に訪れられる。' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 59, '上級編', 'Didn’t your father tell you to keep the window closed [shut] while you were playing the violin?', 'お父さんは(あなたが)バイオリンを弾いている間、窓を閉めておくようにとあなたに言いませんでしたか？' FROM public.lessons WHERE course_key = 'advanced';
INSERT INTO public.learning_items (lesson_id, item_number, grammar, english, japanese) SELECT id, 60, '上級編', 'When his mother told him to keep his room tidy, he asked her why she didn’t tell his sister to do so.', '母親が彼に部屋をきれいにしておきなさいと命じたとき、彼女はなぜ妹にはそうしろと言わないのかと彼女に尋ねた。' FROM public.lessons WHERE course_key = 'advanced';
